const Scrollhandler = (props) => {
  const {
    updScrollPosition
  } = props;

  const [lastPos, set_lastPos] = useState(0);
  const [visible, set_visible] = useState(true);
  const handler = (sp) =>{

    updScrollPosition({pos:sp , show:null});
    if(sp>lastPos && visible){
      if(typeof updScrollPosition === "function"){
        updScrollPosition({pos:sp , show:false});
        set_visible(false);
      }
    }
    else if(sp<lastPos && !visible){
      if(typeof updScrollPosition === "function"){
        updScrollPosition({pos:sp , show:true});
        set_visible(sp);       
      }
    }
    set_lastPos(sp)
  }

  return (<ScrollDecor scrollhandler={handler}/>)
}



